VALUES
  ('locality-8b44517b-moex-00062', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '關於公務員法律責任之敘述，下列何者錯誤？', '["公務員懲戒案件現已從公務員懲戒委員會改制為懲戒法院所審理", "公務員執行職務所涉及之損害賠償責任僅得依據民法規定處理", "依據刑法規定公務員若犯準職務罪時將會加重其刑罰", "依據公務員懲戒法之規定，對於受懲戒之公務員得科以罰款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00063', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '法規命令係由法律授權主管機關訂定，惟立法院仍得對之進行監督。下列敘述何者錯誤？', '["各機關基於法律授權訂定之命令，於發布後，應即送立法院", "依立法院職權行使法之規定，立法院審查時得通過議決，通知行政機關廢止", "立法院應以三讀程序之決議通知機關更正之", "立法院不得以決議逕行將命令變更 30840、31140 31640、31740 31940"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00064', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '國立大學為確保學生具有一定之專業能力，授權各系所訂定考試規則，以明定系所學生取得學分 之條件，下列何者為考試規則之合憲性依據？', '["平等原則", "大學自治", "住民自治", "誠信原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00065', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '有關行政處分無效事由之敘述，下列何者錯誤？', '["未經授權而違背法規有關管轄之規定，主要係指欠缺事物管轄及土地管轄之情形", "所要求或許可之行為構成犯罪者，係指該行為客觀上違反刑罰之法規，而具有違法性", "應以證書方式作成而未給予證書者，係指凡行政處分應依法定方式作成而有所欠缺者", "不能得知處分機關，係指經由形式觀察，無法得知處分機關之情形"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00066', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '行政機關為達成行政目的，得於行政處分作成時附加附款，下列何者非屬此種附款？', '["經濟部核准甲設定礦業權之申請，惟於同意登記設立礦業權通知函中，註明「如出現重大環境 保護之必要或者發生其他重大土地開發事由，得註銷本設定登記」", "A直轄市政府核准乙設立工廠之申請，並於核准函中附加「每年應提供至少新臺幣50萬元回 饋金」條款", "B縣警察局核准丙示威遊行之申請，惟要求遊行路線須避開活動最後主場之火車站站前廣場", "國家通訊傳播委員會核准丁換發營運執照之申請，核發自發照日起5年為限之營運執照"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00067', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '主管機關 A 認定甲所有之房屋為程序違建，乃對甲寄發違章建築補辦手續通知單（下稱補辦通 知單），限期檢齊文件補辦建造執照，如逾期未補辦將進行拆除。甲逾期未補辦，A機關乃寄發 違章建築拆除通知單（下稱拆除通知單），通知甲限期拆除該房屋。如甲未依期限拆除，A機關 決定代行拆除，再向甲徵收費用，前述2件通知單何者可作為執行名義？', '["僅補辦通知單可作為執行名義", "僅拆除通知單可作為執行名義", "2件通知單均具下命性質而屬行政處分，均可為執行名義", "A機關依法須另為催告，2件通知單均不得作為執行名義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00068', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '甲公立學校錄取公費生乙，甲與乙書面約定，乙若違約，甲得逕依約強制執行。乙就讀一學期後 遭受退學，預估應賠償甲新臺幣5萬元，下列敘述何者錯誤？', '["甲與乙之書面約定性質為行政契約", "如生契約爭議，甲應向高等行政法院地方行政訴訟庭起訴", "甲得依約自行逕行行政強制執行", "甲起訴時應繳納裁判費新臺幣2千元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00069', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '關於行政指導，下列敘述何者正確？', '["行政指導應符合授權明確性原則", "行政指導屬於行政契約之一種類型", "行政指導之拒絕，相對人須以書面為之", "行政指導仍有法律優位原則之適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00070', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？', '["一行為違反數個行政法上義務規定且均應處罰鍰時，其罰鍰之金額應依法定罰鍰額最高之規定 裁處，但不得低於各該規定之罰鍰最低額", "違反行政法上義務之處罰，以行為時之法律或自治條例有明文規定者為限", "公立醫院違反廢棄物清理法之行政法上義務，因其屬於公權力主體，主管機關不得裁罰之", "被主管機關接管中之保險公司，仍得作為裁罰之對象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00071', 'locality-8b44517b', 'locality-8b44517b-moex-113-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '某市政府發現民眾甲屋庭院內之樹木，即將傾倒危及民眾，乃直接僱工進入甲屋庭院，鋸倒該樹 木，此行為之法律性質為何？', '["間接強制中之代履行", "行政義務之直接強制", "即時強制", "定暫時狀態之處分 30840、31140 31640、31740 31940"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "306", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL)
